/// Convert HTML to Markdown.
///
/// Returns a heap-allocated [`ConversionResult`] on success, or null on failure.
/// Check `htm_last_error_code` / `htm_last_error_context` for error details.
/// The returned pointer must be freed with `htm_conversion_result_free`.
///
/// If a visitor was attached to `options` via `htm_options_set_visitor`, it will
/// receive callbacks during conversion.
///
/// # Arguments
///
/// - `html`: null-terminated, UTF-8 HTML input. Must not be null.
/// - `options`: optional conversion options (with optional embedded visitor); pass null for defaults.
///
/// # Safety
///
/// `html` must be a valid, non-null, null-terminated UTF-8 string.
/// `options` must be a valid pointer or null.
/// Returned pointer must be freed with `htm_conversion_result_free`.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn htm_convert(
    html: *const std::ffi::c_char,
    options: *const html_to_markdown_rs::ConversionOptions,
) -> *mut html_to_markdown_rs::ConversionResult {
    clear_last_error();

    if html.is_null() {
        set_last_error(1, "Null pointer passed for html");
        return std::ptr::null_mut();
    }

    // SAFETY: null check above guarantees html is a valid pointer; string is valid UTF-8 from caller.
    let html_str = match unsafe { std::ffi::CStr::from_ptr(html) }.to_str() {
        Ok(s) => s,
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in html parameter");
            return std::ptr::null_mut();
        }
    };

    // Clone options out of the pointer.  Any visitor attached via
    // `htm_options_set_visitor` is embedded in options.visitor and will be
    // picked up automatically by the core convert call.
    let options_rs: Option<html_to_markdown_rs::ConversionOptions> = if options.is_null() {
        None
    } else {
        // SAFETY: null check above guarantees options is a valid pointer.
        Some(unsafe { &*options }.clone())
    };

    match html_to_markdown_rs::convert(html_str, options_rs) {
        Ok(result) => Box::into_raw(Box::new(result)),
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

/// Write an error message string into an FFI out-error pointer.
///
/// # Safety
///
/// `out_error` must be null or a valid writable `*mut *mut c_char` pointer.
unsafe fn ffi_set_out_error(out_error: *mut *mut std::ffi::c_char, msg: &str) {
    if !out_error.is_null() {
        if let Ok(cs) = std::ffi::CString::new(msg) {
            // SAFETY: out_error is non-null; caller must free this string.
            unsafe {
                *out_error = cs.into_raw();
            }
        }
    }
}

